using Coefficients = Poincare::Regression::Coefficients;

/* The data was generated by choosing X1 and the coefficients of the regression,
 * then filling Y1 with the regression formula + random()/10. */

void setRegressionPoints(Store* store, int series, int numberOfPoints,
                         const double* xi, const double* yi = nullptr) {
  store->deleteAllPairsOfSeries(series);
  for (int i = 0; i < numberOfPoints; i++) {
    store->set(xi[i], series, 0, i);
    if (yi != nullptr) {
      store->set(yi[i], series, 1, i);
    }
  }
}

void assert_regression_data_is_not_suitable(const double* xi, const double* yi,
                                            const int numberOfPoints,
                                            Model::Type modelType,
                                            bool finite) {
  int series = 0;
  Shared::GlobalContext globalContext;
  Model::Type regressionTypes[] = {Model::Type::None, Model::Type::None,
                                   Model::Type::None, Model::Type::None,
                                   Model::Type::None, Model::Type::None};
  Shared::DoublePairStorePreferences storePreferences;
  Store store(&globalContext, &storePreferences, regressionTypes);

  setRegressionPoints(&store, series, numberOfPoints, xi, yi);
  store.setSeriesRegressionType(series, modelType);
  Shared::StoreContext context(&store, &globalContext);

  quiz_assert(!store.coefficientsAreDefined(series, &context, finite));
}

void assert_regression_is(const double* xi, const double* yi,
                          const int numberOfPoints, Model::Type modelType,
                          const Coefficients& trueCoefficients, double trueR,
                          double trueR2, double trueResidualStdDev,
                          bool acceptNAN = false,
                          bool exactCoefficients = false) {
  int series = 0;
  Shared::GlobalContext globalContext;
  Model::Type regressionTypes[] = {Model::Type::None, Model::Type::None,
                                   Model::Type::None, Model::Type::None,
                                   Model::Type::None, Model::Type::None};
  Shared::DoublePairStorePreferences storePreferences;
  Store store(&globalContext, &storePreferences, regressionTypes);

  setRegressionPoints(&store, series, numberOfPoints, xi, yi);
  store.setSeriesRegressionType(series, modelType);
  Shared::StoreContext context(&store, &globalContext);

  double precision = 1e-2;
  // When expected value is null, expect a stronger precision
  double nullExpectedPrecision = 1e-9;

  // Compute and compare the coefficients
  double* coefficients = store.coefficientsForSeries(series, &context);
  int numberOfCoefs = store.modelForSeries(series)->numberOfCoefficients();

  // Move the double* to an std::array for easier debugging
  Poincare::Regression::Coefficients coefficientsArray;
  memmove(coefficientsArray.data(), coefficients,
          numberOfCoefs * sizeof(double));

  /* TODO: we could use the std::equal or std::for_each algorithms here, to
   * factorize the "for" loop */
  for (int i = 0; i < numberOfCoefs; i++) {
    bool cond = roughly_equal(coefficients[i], trueCoefficients[i],
                              exactCoefficients ? 0.0 : precision, acceptNAN,
                              exactCoefficients ? 0.0 : nullExpectedPrecision);
#if POINCARE_TREE_LOG
    if (!cond) {
      std::cout << "Coefficient of regression different:" << std::endl;
      std::cout << "\tExpected:" << trueCoefficients[i] << std::endl;
      std::cout << "\t     Got:" << coefficients[i] << std::endl;
    }
#endif
    quiz_assert(cond);
  }

  double r = store.correlationCoefficient(series);
  double r2 = store.determinationCoefficientForSeries(series, &globalContext);
  double sr = store.residualStandardDeviation(series, &globalContext);

  if (!Store::DisplayR(modelType)) {
    assert(std::isnan(r) && std::isnan(trueR));
  } else {
    quiz_assert(r >= -1.0 && r <= 1.0);
    quiz_assert(
        roughly_equal(r, trueR, precision, false, nullExpectedPrecision));
  }

  if (Store::DisplayR(modelType) && Store::DisplayRSquared(modelType)) {
    // Ensure r^2 is r*r
    quiz_assert(r * r == r2);
  }

  if (!Store::DisplayR2(modelType) && !Store::DisplayRSquared(modelType)) {
    assert(std::isnan(r2) && std::isnan(trueR2));
  } else {
    // Compute and check R2/r^2 value and sign
    quiz_assert(r2 <= 1.0 &&
                (r2 >= 0.0 || modelType == Model::Type::Proportional));
    bool cond =
        roughly_equal(r2, trueR2, precision, false, nullExpectedPrecision);
#if POINCARE_TREE_LOG
    if (!cond) {
      std::cout << "R^2 different:" << std::endl;
      std::cout << "\tExpected:" << trueR2 << std::endl;
      std::cout << "\t     Got:" << r2 << std::endl;
    }
#endif
    quiz_assert(cond);
  }

  bool cond = roughly_equal(sr, trueResidualStdDev, precision, true,
                            nullExpectedPrecision);
#if POINCARE_TREE_LOG
  if (!cond) {
    std::cout << "Residual Std dev different:" << std::endl;
    std::cout << "\tExpected:" << trueResidualStdDev << std::endl;
    std::cout << "\t     Got:" << sr << std::endl;
  }
#endif
  quiz_assert(cond);
}

QUIZ_CASE(regression_linear) {
  constexpr double x[] = {1.0, 8.0, 14.0, 79.0};
  constexpr double y[] = {-3.581, 20.296, 40.676, 261.623};
  constexpr Coefficients coefficientsAxpb = {3.4, -7.0};
  constexpr Coefficients coefficientsApbx = {-7.0, 3.4};
  constexpr double r = 1.0;
  constexpr double r2 = 1.0;
  constexpr double sr = 0.0425;
  assert_regression_is(x, y, std::size(x), Model::Type::LinearAxpb,
                       coefficientsAxpb, r, r2, sr);
  assert_regression_is(x, y, std::size(x), Model::Type::LinearApbx,
                       coefficientsApbx, r, r2, sr);
}

